// Parse an RSS feed item into an xstockstrat signal.
// Adapt the field extraction to match the specific feed structure.
//
// Common RSS fields available:
//   item.title, item.content, item.contentSnippet, item.link,
//   item.pubDate, item.creator, item.categories

const item = $input.item.json;
const title = item.title || '';
const content = item.content || item.contentSnippet || item.summary || '';
const link = item.link || item.url || '';
const pubDate = item.pubDate || item.isoDate || new Date().toISOString();

// --- Source detection ---
// Customize this URL-based source mapping for each registered feed
let source = 'unknown';
if (link.includes('unusualwhales.com')) source = 'unusual_whales';
else if (link.includes('marketwatch.com') || link.includes('wsj.com')) source = 'marketwatch';
else if (link.includes('dividendology.com')) source = 'dividendology';
else if (link.includes('purpowerpicks') || link.includes('pure-power')) source = 'pure_power_picks';
else if (link.includes('simplywallst.com')) source = 'simply_wall_st';

// --- Ticker extraction ---
const tickerMatch = title.match(/\$([A-Z]{1,5})/) ||
                    content.match(/\$([A-Z]{1,5})/);
const symbol = tickerMatch ? tickerMatch[1] : null;

if (!symbol || source === 'unknown') return [];

// --- Direction ---
const text = (title + ' ' + content).toLowerCase();
let direction = 'watchlist';
if (/\b(buy|bullish|long|call|upgrade|undervalued|accumulate)\b/.test(text)) direction = 'buy';
else if (/\b(sell|bearish|short|put|downgrade|overvalued|reduce)\b/.test(text)) direction = 'sell';
else if (/\b(hold|neutral|maintain)\b/.test(text)) direction = 'hold';

// --- Conviction from categories/tags ---
let conviction = 0.5;
if (Array.isArray(item.categories)) {
  if (item.categories.some(c => /high conviction|strong/i.test(c))) conviction = 0.85;
  else if (item.categories.some(c => /low conviction|weak/i.test(c))) conviction = 0.3;
}

// --- Tags ---
const tags = [];
if (/unusual option|sweep/i.test(text)) tags.push('unusual_options');
if (/call sweep/i.test(text)) tags.push('call_sweep');
if (/put sweep/i.test(text)) tags.push('put_sweep');
if (/dark pool/i.test(text)) tags.push('dark_pool');
if (/dividend|ex-div/i.test(text)) tags.push('dividend', 'income');
if (/upgrade/i.test(text)) tags.push('analyst', 'upgrade');
if (/downgrade/i.test(text)) tags.push('analyst', 'downgrade');
if (/momentum|swing/i.test(text)) tags.push('momentum');
if (/earnings/i.test(text)) tags.push('earnings');

// --- Valid window: pubDate + 5 days ---
const validFrom = new Date(pubDate).toISOString();
const validUntil = new Date(new Date(pubDate).getTime() + 5 * 24 * 60 * 60 * 1000).toISOString();

return [{
  json: {
    source,
    symbol,
    direction,
    conviction,
    valid_from: validFrom,
    valid_until: validUntil,
    headline: title.slice(0, 255),
    raw_url: link,
    tags,
  }
}];
